// ───────────────────────────────────────────────────────────────
// MODULE: Incremental Index
// ───────────────────────────────────────────────────────────────
// Feature catalog: Deferred lexical-only indexing
// Mtime-based incremental indexing for fast re-indexing
// Node stdlib
import { createHash } from 'node:crypto';
import * as fs from 'fs';
import * as path from 'path';

// External packages
import type Database from 'better-sqlite3';

// Internal modules
import { getCanonicalPathKey } from '../utils/canonical-path.js';
import { extractSpecFolder, extractDocumentType } from '../parsing/memory-parser.js';
import { canonicalFingerprint } from './canonical-fingerprint.js';
import { createMemoStore } from './memo.js';

/* ───────────────────────────────────────────────────────────────

display.text:
// ───────────────────────────────────────────────────────────────
// MODULE: Incremental Index
// ───────────────────────────────────────────────────────────────
// Feature catalog: Deferred lexical-only indexing
// Mtime-based incremental indexing for fast re-indexing
// Node stdlib
import { createHash } from 'node:crypto';
import * as fs from 'fs';
import * as path from 'path';

// External packages
import type Database from 'better-sqlite3';

// Internal modules
import { getCanonicalPathKey } from '../utils/canonical-path.js';
import { extractSpecFolder, extractDocumentType } from '../parsing/memory-parser.js';
import { canonicalFingerprint } from './canonical-fingerprint.js';
import { createMemoStore } from './memo.js';

/* ───────────────────────────────────────────────────────────────
   1. CONSTANTS
----------------------------------------------------------------*/

const MTIME_FAST_PATH_MS = 1000; // Skip if mtime within 1 second
const DEFAULT_ORPHAN_SWEEP_LIMIT = 200;

/* ───────────────────────────────────────────────────────────────
   2. INTERFACES
----------------------------------------------------------------*/

interface FileMetadata {
  path: string;
  mtime: number;
  size: number;
  exists: boolean;
}

interface StoredMetadata {
  file_path: string;
  canonical_file_path?: string | null;
  file_mtime_ms: number | null;
  content_hash: string | null;
  embedding_status: string;
}

type IndexDecision = 'skip' | 'reindex' | 'new' | 'deleted' | 'modified' | 'unknown';

interface CategorizedFiles {
  toIndex: string[];
  toUpdate: string[];
  toSkip: string[];
  toDelete: string[];
}

interface IndexedPathRow {
  file_path: string;
  canonical_file_path?: string | null;
}

interface IndexedRecordRow extends IndexedPathRow {
  id: number;
}

interface OrphanSweepOptions {
  limit?: number;
  cursor?: number;
}

interface OrphanSweepResult {
  swept: number;
  nextCursor: number | null;
  scannedRows: number;
  orphanRecordIds: number[];
}

/* ───────────────────────────────────────────────────────────────
   3. MODULE STATE
----------------------------------------------------------------*/

let db: Database.Database | null = null;
let canonicalPathColumnAvailable: boolean | null = null;
let documentTypeColumnAvailable: boolean | null = null;

function init(database: Database.Database): void {
  db = database;
  canonicalPathColumnAvailable = null;
  documentTypeColumnAvailable = null;
}

function hasCanonicalPathColumn(): boolean {
  if (!db) return false;

  if (canonicalPathColumnAvailable !== null) {
    return canonicalPathColumnAvailable;
  }

  try {
    const columns = (db.prepare('PRAGMA table_info(memory_index)').all() as Array<{ name: string }>);
    canonicalPathColumnAvailable = columns.some((column) => column.name === 'canonical_file_path');
  } catch {
    canonicalPathColumnAvailable = false;
  }

  return canonicalPathColumnAvailable;
}

function hasDocumentTypeColumn(): boolean {
  if (!db) return false;

  if (documentTypeColumnAvailable !== null) {
    return documentTypeColumnAvailable;
  }

  try {
    const columns = (db.prepare('PRAGMA table_info(memory_index)').all() as Array<{ name: string }>);
    documentTypeColumnAvailable = columns.some((column) => column.name === 'document_type');
  } catch {
    documentTypeColumnAvailable = false;
  }

  return documentTypeColumnAvailable;
}

/* ───────────────────────────────────────────────────────────────
   4. FILE METADATA
----------------------------------------------------------------*/

function getFileMetadata(filePath: string): FileMetadata {
  try {
    const stats = fs.statSync(filePath);
    return {
      path: filePath,
      mtime: stats.mtimeMs,
      size: stats.size,
      exists: true,
    };
  } catch {
    return {
      path: filePath,
      mtime: 0,
      size: 0,
      exists: false,
    };
  }
}

function getStoredMetadata(filePath: string): StoredMetadata | null {
  if (!db) return null;

  try {
    const canonicalPath = getCanonicalPathKey(filePath);

    const row = hasCanonicalPathColumn()
      ? (db.prepare(`
          SELECT file_path, canonical_file_path, file_mtime_ms, content_hash, embedding_status
          FROM memory_index
          WHERE canonical_file_path = ? OR file_path = ?
          ORDER BY CASE WHEN canonical_file_path = ? THEN 0 ELSE 1 END, id DESC
          LIMIT 1
        `) as Database.Statement).get(canonicalPath, filePath, canonicalPath) as StoredMetadata | undefined
      : (db.prepare(`
          SELECT file_path, file_mtime_ms, content_hash, embedding_status
          FROM memory_index
          WHERE file_path = ?
        `) as Database.Statement).get(filePath) as StoredMetadata | undefined;

    return row || null;
  } catch (error: unknown) {
    const msg = error instanceof Error ? error.message : String(error);
    console.warn(`[incremental-index] getStoredMetadata error: ${msg}`);
    return null;
  }
}

function computeFileContentHash(filePath: string): string | null {
  try {
    const content = fs.readFileSync(filePath);
    return createHash('sha256').update(content).digest('hex');
  } catch {
    return null;
  }
}

/* ───────────────────────────────────────────────────────────────
   5. DECISION LOGIC
----------------------------------------------------------------*/

/**
 * 6-path decision logic for whether a file needs re-indexing.
 */
function shouldReindex(filePath: string): IndexDecision {
  const fileInfo = getFileMetadata(filePath);

  // Path 1: File doesn't exist on disk
  if (!fileInfo.exists) {
    const stored = getStoredMetadata(filePath);
    if (stored) return 'deleted';
    return 'skip';
  }

  // Path 2: No stored metadata (new file)
  const stored = getStoredMetadata(filePath);
  if (!stored) return 'new';

  // Path 3: No stored mtime (legacy entry, needs re-indexing)
  if (stored.file_mtime_ms === null) return 'reindex';

  // Path 4: Mtime unchanged (fast path - skip)
  if (Math.abs(fileInfo.mtime - stored.file_mtime_ms) < MTIME_FAST_PATH_MS) {
    // Still check if embedding status is pending
    if (stored.embedding_status === 'pending' || stored.embedding_status === 'failed') {
      return 'reindex';
    }

    if (stored.content_hash) {
      const currentContentHash = computeFileContentHash(filePath);
      if (currentContentHash && currentContentHash !== stored.content_hash) {
        return 'modified';
      }
    }

    return 'skip';
  }

  // Path 5: Mtime changed (file modified)
  return 'modified';
}

/* ───────────────────────────────────────────────────────────────
   6. MTIME MANAGEMENT
----------------------------------------------------------------*/

function updateFileMtime(filePath: string, mtimeMs: number): boolean {
  if (!db) return false;

  try {
    const canonicalPath = getCanonicalPathKey(filePath);

    const result = hasCanonicalPathColumn()
      ? (db.prepare(`
          UPDATE memory_index
          SET file_mtime_ms = ?
          WHERE canonical_file_path = ? OR file_path = ?
        `) as Database.Statement).run(mtimeMs, canonicalPath, filePath)
      : (db.prepare(`
          UPDATE memory_index
          SET file_mtime_ms = ?
          WHERE file_path = ?
        `) as Database.Statement).run(mtimeMs, filePath);

    return (result as { changes: number }).changes > 0;
  } catch (error: unknown) {
    const msg = error instanceof Error ? error.message : String(error);
    console.warn(`[incremental-index] updateFileMtime error: ${msg}`);
    return false;
  }
}

function setIndexedMtime(filePath: string): boolean {
  const fileInfo = getFileMetadata(filePath);
  if (!fileInfo.exists) return false;
  return updateFileMtime(filePath, fileInfo.mtime);
}

/* ───────────────────────────────────────────────────────────────
   7. BATCH OPERATIONS
----------------------------------------------------------------*/

function categorizeFilesForIndexing(filePaths: string[]): CategorizedFiles {
  const result: CategorizedFiles = {
    toIndex: [],
    toUpdate: [],
    toSkip: [],
    toDelete: [],
  };

  for (const filePath of filePaths) {
    const decision = shouldReindex(filePath);

    switch (decision) {
      case 'new':
        result.toIndex.push(filePath);
        break;
      case 'modified':
      case 'reindex':
        result.toUpdate.push(filePath);
        break;
      case 'deleted':
        result.toDelete.push(filePath);
        break;
      case 'skip':
      default:
        result.toSkip.push(filePath);
        break;
    }
  }

  // Include stale indexed paths that are no longer discovered on disk.
  // Without this pass, removed files never enter toDelete during normal scans
  // Because discovery only returns files that currently exist.
  const staleIndexedPaths = listStaleIndexedPaths(filePaths);
  if (staleIndexedPaths.length > 0) {
    const seenDeleteKeys = new Set<string>(result.toDelete.map((filePath) => getCanonicalPathKey(filePath)));
    for (const stalePath of staleIndexedPaths) {
      const staleKey = getCanonicalPathKey(stalePath);
      if (!seenDeleteKeys.has(staleKey)) {
        result.toDelete.push(stalePath);
        seenDeleteKeys.add(staleKey);
      }
    }
  }

  return result;
}

function listStaleIndexedPaths(scannedFilePaths: string[]): string[] {
  if (!db) return [];

  const scannedCanonicalPaths = new Set(scannedFilePaths.map((filePath) => getCanonicalPathKey(filePath)));
  const stalePaths = new Set<string>();

  try {
    const rows = hasCanonicalPathColumn()
      ? (db.prepare(`
          SELECT DISTINCT file_path, canonical_file_path
          FROM memory_index
          WHERE file_path IS NOT NULL AND file_path != ''
        `) as Database.Statement).all() as IndexedPathRow[]
      : (db.prepare(`
          SELECT DISTINCT file_path
          FROM memory_index
          WHERE file_path IS NOT NULL AND file_path != ''
        `) as Database.Statement).all() as IndexedPathRow[];

    for (const row of rows) {
      if (!row || typeof row.file_path !== 'string' || row.file_path.length === 0) {
        continue;
      }

      const rowCanonicalPath = typeof row.canonical_file_path === 'string' && row.canonical_file_path.length > 0
        ? row.canonical_file_path
        : getCanonicalPathKey(row.file_path);

      if (scannedCanonicalPaths.has(rowCanonicalPath)) {
        continue;
      }

      const filePathExists = getFileMetadata(row.file_path).exists;
      const canonicalPathExists = typeof row.canonical_file_path === 'string' && row.canonical_file_path.length > 0
        ? getFileMetadata(row.canonical_file_path).exists
        : false;

      if (!filePathExists && !canonicalPathExists) {
        stalePaths.add(row.file_path);
      }
    }
  } catch (error: unknown) {
    const msg = error instanceof Error ? error.message : String(error);
    console.warn(`[incremental-index] listStaleIndexedPaths error: ${msg}`);
  }

  return Array.from(stalePaths);
}

function listIndexedRecordIdsForDeletedPaths(filePaths: string[]): number[] {
  if (!db || filePaths.length === 0) return [];

  const ids = new Set<number>();
  const seenLookupKeys = new Set<string>();

  try {
    for (const filePath of filePaths) {
      if (typeof filePath !== 'string' || filePath.length === 0) {
        continue;
      }

      const canonicalPath = getCanonicalPathKey(filePath);
      const lookupKey = `${canonicalPath}::${filePath}`;
      if (seenLookupKeys.has(lookupKey)) {
        continue;
      }
      seenLookupKeys.add(lookupKey);

      const rows = hasCanonicalPathColumn()
        ? (db.prepare(`
            SELECT id, file_path, canonical_file_path
            FROM memory_index
            WHERE canonical_file_path = ? OR file_path = ?
          `) as Database.Statement).all(canonicalPath, filePath) as IndexedRecordRow[]
        : (db.prepare(`
            SELECT id, file_path
            FROM memory_index
            WHERE file_path = ?
          `) as Database.Statement).all(filePath) as IndexedRecordRow[];

      for (const row of rows) {
        if (!row || typeof row.id !== 'number') {
          continue;
        }

        const rowFileExists = typeof row.file_path === 'string' && row.file_path.length > 0
          ? getFileMetadata(row.file_path).exists
          : false;
        const rowCanonicalExists = typeof row.canonical_file_path === 'string' && row.canonical_file_path.length > 0
          ? getFileMetadata(row.canonical_file_path).exists
          : false;

        if (rowFileExists || rowCanonicalExists) {
          continue;
        }

        ids.add(row.id);
      }
    }
  } catch (error: unknown) {
    const msg = error instanceof Error ? error.message : String(error);
    console.warn(`[incremental-index] listIndexedRecordIdsForDeletedPaths error: ${msg}`);
    return [];
  }

  return Array.from(ids).sort((a, b) => a - b);
}

function normalizeOrphanSweepLimit(limit?: number): number {
  if (typeof limit !== 'number' || !Number.isFinite(limit) || limit <= 0) {
    return DEFAULT_ORPHAN_SWEEP_LIMIT;
  }

  return Math.max(1, Math.floor(limit));
}

function indexedRecordIsAbsent(row: IndexedRecordRow): boolean {
  const rowFileExists = typeof row.file_path === 'string' && row.file_path.length > 0
    ? getFileMetadata(row.file_path).exists
    : false;
  const rowCanonicalExists = typeof row.canonical_file_path === 'string' && row.canonical_file_path.length > 0
    ? getFileMetadata(row.canonical_file_path).exists
    : false;

  return !rowFileExists && !rowCanonicalExists;
}

function sweepOrphanIndexRows(options: OrphanSweepOptions = {}): OrphanSweepResult {
  if (!db) {
    return { swept: 0, nextCursor: null, scannedRows: 0, orphanRecordIds: [] };
  }

  const limit = normalizeOrphanSweepLimit(options.limit);
  const cursor = typeof options.cursor === 'number' && Number.isFinite(options.cursor) && options.cursor > 0
    ? Math.floor(options.cursor)
    : 0;

  try {
    const rows = hasCanonicalPathColumn()
      ? (db.prepare(`
          SELECT id, file_path, canonical_file_path
          FROM memory_index
          WHERE id > ?
            AND file_path IS NOT NULL
            AND file_path != ''
          ORDER BY id ASC
          LIMIT ?
        `) as Database.Statement).all(cursor, limit) as IndexedRecordRow[]
      : (db.prepare(`
          SELECT id, file_path
          FROM memory_index
          WHERE id > ?
            AND file_path IS NOT NULL
            AND file_path != ''
          ORDER BY id ASC
          LIMIT ?
        `) as Database.Statement).all(cursor, limit) as IndexedRecordRow[];

    const orphanRecordIds: number[] = [];
    for (const row of rows) {
      if (!row || typeof row.id !== 'number') {
        continue;
      }
      if (indexedRecordIsAbsent(row)) {
        orphanRecordIds.push(row.id);
      }
    }

    return {
      swept: orphanRecordIds.length,
      nextCursor: rows.length === limit ? rows[rows.length - 1]?.id ?? null : null,
      scannedRows: rows.length,
      orphanRecordIds,
    };
  } catch (error: unknown) {
    const msg = error instanceof Error ? error.message : String(error);
    console.warn(`[incremental-index] sweepOrphanIndexRows error: ${msg}`);
    return { swept: 0, nextCursor: null, scannedRows: 0, orphanRecordIds: [] };
  }
}

/* ───────────────────────────────────────────────────────────────
   7b. MOVE RECONCILIATION
----------------------------------------------------------------*/

interface MoveReconcileCandidate {
  oldPath: string;
  newPath: string;
  rowId: number;
  docType: string;
}

interface ReconcileMovesResult {
  reconciled: MoveReconcileCandidate[];
  filteredToDelete: string[];
  filteredToIndex: string[];
}

interface IncrementalChunkFingerprint {
  chunkId: string;
  chunkFingerprint: string;
}

interface MemoizedPlanningInput {
  componentPath: string;
  canonicalInput: unknown;
  codeHash: string;
  chunks?: IncrementalChunkFingerprint[];
}

interface MemoizedPlanningOptions {
  invalidateDependents?: boolean;
}

interface MemoizedPlanningResult {
  memoHits: number;
  memoMisses: number;
  chunkHits: number;
  chunkMisses: number;
  dependencyInvalidated: number;
  changedComponentPaths: string[];
  unchangedComponentPaths: string[];
  invalidatedComponentPaths: string[];
}

function reconcileMoves(
  toDelete: string[],
  toIndex: string[],
): ReconcileMovesResult {
  if (!db || toDelete.length === 0 || toIndex.length === 0) {
    return { reconciled: [], filteredToDelete: toDelete, filteredToIndex: toIndex };
  }

  // Build a map: packet_id → [{newPath, docType, newGrandparent}] from the toIndex files.
  // Reads graph-metadata.json from the NEW location only — the old one may be gone after a move.
  const newByPacketId = new Map<string, Array<{ newPath: string; docType: string; newGrandparent: string }>>();
  for (const newPath of toIndex) {
    try {
      const newSpecFolder = path.dirname(newPath);
      const graphMetaPath = path.join(newSpecFolder, 'graph-metadata.json');
      if (!fs.existsSync(graphMetaPath)) continue;
      const raw = fs.readFileSync(graphMetaPath, 'utf-8');
      const meta = JSON.parse(raw) as { packet_id?: string };
      const packetId = meta?.packet_id;
      if (typeof packetId !== 'string' || packetId.length === 0) continue;
      const docType = path.basename(newPath, path.extname(newPath));
      const newGrandparent = path.dirname(newSpecFolder);
      if (!newByPacketId.has(packetId)) newByPacketId.set(packetId, []);
      newByPacketId.get(packetId)!.push({ newPath, docType, newGrandparent });
    } catch {
      // skip unreadable or non-JSON graph-metadata
    }
  }

  if (newByPacketId.size === 0) {
    return { reconciled: [], filteredToDelete: toDelete, filteredToIndex: toIndex };
  }

  const reconciledOldPaths = new Set<string>();
  const reconciledNewPaths = new Set<string>();
  const reconciled: MoveReconcileCandidate[] = [];

  // Iterate from the NEW side: for each new path whose folder still carries a packet_id,
  // find the corresponding old path in toDelete by matching grandparent directory + basename
  // (a sibling folder rename within the same parent). The packet_id only gates which new
  // paths are eligible — the actual old→new pairing is grandparent + basename plus the
  // DB uniqueness guards below; it does NOT match the old row by its packet_id (the old
  // graph-metadata.json may be gone, and memory_index has no packet_id column). To avoid
  // repointing across mismatched document kinds, the stored document_type is cross-checked
  // against the doc type derived from the new path before the in-place update.
  const docTypeAvailable = hasDocumentTypeColumn();
  const selectSql = docTypeAvailable
    ? `SELECT id, document_type FROM memory_index WHERE (file_path = ? OR canonical_file_path = ?) AND embedding_status != 'failed' LIMIT 2`
    : `SELECT id FROM memory_index WHERE (file_path = ? OR canonical_file_path = ?) AND embedding_status != 'failed' LIMIT 2`;
  for (const [, newCandidates] of newByPacketId) {
    for (const { newPath, docType, newGrandparent } of newCandidates) {
      if (reconciledNewPaths.has(newPath)) continue;

      const newBasename = path.basename(newPath);

      // Find toDelete paths that are sibling renames: same grandparent dir, same basename.
      // A sibling rename means only the immediate spec folder name changed (e.g. 012-old → 012-new).
      const siblingDeleted = toDelete.filter(oldPath =>
        !reconciledOldPaths.has(oldPath) &&
        path.basename(oldPath) === newBasename &&
        path.dirname(path.dirname(oldPath)) === newGrandparent
      );

      if (siblingDeleted.length !== 1) continue; // uniqueness required

      const oldPath = siblingDeleted[0];
      const canonicalOld = getCanonicalPathKey(oldPath);

      // Verify in DB: exactly one live row for this old path (uniqueness guard).
      const rows = db!.prepare(selectSql).all(oldPath, canonicalOld) as Array<{ id: number; document_type?: string | null }>;
      if (rows.length !== 1) continue;

      // Cross-verify document kind: the stored document_type must agree with the doc type
      // derived from the new path. Skip rows whose stored type diverged from the new file
      // (e.g. a generic 'memory' row that happens to share a basename), preventing a
      // mismatched repoint. Tolerant when the column is absent (legacy/test schemas).
      if (docTypeAvailable) {
        const storedDocType = rows[0].document_type ?? null;
        if (storedDocType !== null && storedDocType !== extractDocumentType(newPath)) continue;
      }

      const rowId = rows[0].id;
      const newCanonical = getCanonicalPathKey(newPath);
      const newSpecFolder = extractSpecFolder(newPath);
      const newMtime = (() => {
        try { return fs.statSync(newPath).mtimeMs; } catch { return null; }
      })();

      // Update the row's path in place (preserves embedding, id, history). A reconciled
      // move is a folder rename, so spec_folder is repointed with the same canonicalization
      // indexMemoryFile/migration 23 use — otherwise WHERE spec_folder=? grouping goes stale.
      const updated = db!.prepare(`
        UPDATE memory_index
        SET file_path = ?,
            canonical_file_path = ?,
            spec_folder = ?,
            file_mtime_ms = ?,
            updated_at = datetime('now')
        WHERE id = ?
          AND embedding_status != 'failed'
      `).run(newPath, newCanonical, newSpecFolder, newMtime, rowId);

      if ((updated as { changes: number }).changes !== 1) continue;

      reconciledOldPaths.add(oldPath);
      reconciledNewPaths.add(newPath);
      reconciled.push({ oldPath, newPath, rowId, docType });
      console.error(`[incremental-index] Move reconciled: ${newBasename} ${oldPath} → ${newPath} (row ${rowId}, embedding preserved)`);
    }
  }

  return {
    reconciled,
    filteredToDelete: toDelete.filter(p => !reconciledOldPaths.has(p)),
    filteredToIndex: toIndex.filter(p => !reconciledNewPaths.has(p)),
  };
}

function batchUpdateMtimes(filePaths: string[]): { updated: number; failed: number } {
  if (!db) return { updated: 0, failed: filePaths.length };

// ───────────────────────────────────────────────────────────────
// MODULE: File Watcher
// ───────────────────────────────────────────────────────────────

/* ───────────────────────────────────────────────────────────────
   1. IMPORTS
──────────────────────────────────────────────────────────────── */

import fs from 'node:fs/promises';
import path from 'node:path';
import { createHash } from 'node:crypto';
import { BetterSqliteContentionPolicy } from '../storage/ports/contention-policy.js';

// Feature catalog: Real-time filesystem watching with chokidar
// Feature catalog: Watcher delete/rename cleanup

/* ───────────────────────────────────────────────────────────────
   2. TYPES
──────────────────────────────────────────────────────────────── */

/**
 * Describes the WatcherConfig shape.
 */
export interface WatcherConfig {
  paths: string[];
  reindexFn: (filePath: string) => Promise<unknown>;
  removeFn?: (filePath: string) => Promise<unknown>;
  debounceMs?: number;
  watchFactory?: (paths: string[], options: Record<string, unknown>) => FSWatcher;
}

/**
 * Describes the FSWatcher shape.
 */
export interface FSWatcher {
  on: (event: string, listener: (...args: unknown[]) => void) => FSWatcher;
  close: () => Promise<void>;
}

interface ChokidarModule {
  default: {
    watch: (paths: string[], options: Record<string, unknown>) => FSWatcher;
  };
}

/* ───────────────────────────────────────────────────────────────
   3. CONSTANTS
──────────────────────────────────────────────────────────────── */

const DEFAULT_DEBOUNCE_MS = 2000;
const RETRY_DELAYS_MS = [1000, 2000, 4000];
const MAX_BUSY_RETRIES = RETRY_DELAYS_MS.length;
const busyRetryPolicy = new BetterSqliteContentionPolicy({ retryable: isSqliteBusyError });

// Watcher metrics counters
let filesReindexed = 0;
let totalReindexTimeMs = 0;
let chokidarModule: ChokidarModule | null = null;
let chokidarModulePromise: Promise<ChokidarModule | null> | null = null;
let chokidarModuleLoadError: string | null = null;

/** Return accumulated watcher metrics for diagnostics. */
export function getWatcherMetrics(): { filesReindexed: number; avgReindexTimeMs: number } {
  return {
    filesReindexed,
    avgReindexTimeMs: filesReindexed > 0 ? Math.round(totalReindexTimeMs / filesReindexed) : 0,
  };
}

export function resetWatcherMetrics(): void {
  filesReindexed = 0;
  totalReindexTimeMs = 0;
}

/* ───────────────────────────────────────────────────────────────
   4. HELPERS
──────────────────────────────────────────────────────────────── */

function sleep(ms: number): Promise<void> {
  return new Promise((resolve) => setTimeout(resolve, ms));
}

/**
 * Coordinates early wake-up of in-flight retry sleeps so a watcher shutdown
 * never has to wait for a pending backoff timer to expire. A retry sleep
 * registers a `wake` callback; `wakeAll()` settles every outstanding sleep
 * immediately, letting each one re-check its abort condition. This keeps
 * `close()` from blocking on a non-cancellable timer (and from deadlocking
 * under fake timers, where the backoff timeout would otherwise never fire).
 */
interface RetryWaker {
  register(wake: () => void): () => void;
  wakeAll(): void;
}

function createRetryWaker(): RetryWaker {
  const waiters = new Set<() => void>();
  let woken = false;
  return {
    register(wake: () => void): () => void {
      // Sticky after wakeAll(): a sleep entered after shutdown began is woken
      // at once, so a task that hits SQLITE_BUSY mid-close still exits promptly
      // instead of stalling close() on a fresh retry timer.
      if (woken) {
        wake();
        return () => undefined;
      }
      waiters.add(wake);
      return () => { waiters.delete(wake); };
    },
    wakeAll(): void {
      woken = true;
      const pending = Array.from(waiters);
      waiters.clear();
      for (const wake of pending) {
        wake();
      }
    },
  };
}

/**
 * Sleep that resolves either when `ms` elapses or when woken early via the
 * supplied waker. On early wake the backoff timer is cleared so no stray timer
 * survives shutdown.
 */
function abortableSleep(ms: number, waker?: RetryWaker): Promise<void> {
  if (!waker) {
    return sleep(ms);
  }
  return new Promise((resolve) => {
    let settled = false;
    let unregister = (): void => undefined;
    const finish = (): void => {
      if (settled) return;
      settled = true;
      clearTimeout(timer);
      unregister();
      resolve();
    };
    const timer = setTimeout(finish, ms);
    unregister = waker.register(finish);
  });
}

async function loadChokidarModule(): Promise<ChokidarModule | null> {
  if (chokidarModule !== null) {
    return chokidarModule;
  }
  if (chokidarModulePromise !== null) {
    return chokidarModulePromise;
  }

  const loadPromise = (async (): Promise<ChokidarModule | null> => {
    try {
      chokidarModule = await import('chokidar') as ChokidarModule;
      chokidarModuleLoadError = null;
      return chokidarModule;
    } catch (error: unknown) {
      chokidarModuleLoadError = error instanceof Error ? error.message : String(error);
      return null;
    }
  })();

  chokidarModulePromise = loadPromise;
  try {
    return await loadPromise;
  } finally {
    if (chokidarModulePromise === loadPromise) {
      chokidarModulePromise = null;
    }
  }
}

function getWatchFactory(): (paths: string[], options: Record<string, unknown>) => FSWatcher {
  if (chokidarModule?.default?.watch) {
    return chokidarModule.default.watch;
  }

  if (chokidarModulePromise === null) {
    void loadChokidarModule();
  }
  const loadErrorSuffix = chokidarModuleLoadError
    ? ` Last module resolution error: ${chokidarModuleLoadError}`
    : '';
  throw new Error(`chokidar module is still loading or unavailable; retry startFileWatcher once lazy import completes.${loadErrorSuffix}`);
}

function isDotfilePath(filePath: string): boolean {
  const parts = filePath
    .split(/[/\\]/)
    .filter((part) => part.length > 0);

  for (const part of parts) {
    if (!part.startsWith('.') || part.length <= 1) {
      continue;
    }

    // .opencode is a first-class workspace root for Spec Kit assets.
    // Treating it as a dotfile path would suppress watcher events for
    // .opencode/specs/** and break auto re-indexing in default layouts.
    if (part === '.opencode') {
      continue;
    }

    return true;
  }

  return false;
}

function isMarkdownPath(filePath: string): boolean {
  return filePath.toLowerCase().endsWith('.md');
}

function shouldIgnoreWatchTarget(targetPath: string): boolean {
  if (isDotfilePath(targetPath)) return true;
  const basename = path.basename(targetPath);
  return basename.startsWith('.');
}

function getWatchScopedPath(targetPath: string, watchRoots: string[]): string | null {
  const resolvedTarget = path.resolve(targetPath);

  for (const watchRoot of watchRoots) {
    const relativeTarget = path.relative(watchRoot, resolvedTarget);
    const isWithinRoot = relativeTarget === '' || (
      !relativeTarget.startsWith(`..${path.sep}`) &&
      relativeTarget !== '..' &&
      !path.isAbsolute(relativeTarget)
    );

    if (isWithinRoot) {
      return relativeTarget;
    }
  }

  return null;
}

function isSqliteBusyError(error: unknown): boolean {
  const message = error instanceof Error ? error.message : String(error);
  const code = (error as { code?: unknown })?.code;
  return code === 'SQLITE_BUSY' || /SQLITE_BUSY/i.test(message);
}

async function hashFileContent(filePath: string): Promise<string> {
  const content = await fs.readFile(filePath);
  return createHash('sha256').update(content).digest('hex');
}

interface BusyRetryOptions {
  shouldAbort?: () => boolean;
  waker?: RetryWaker;
}

async function withBusyRetry(
  operation: () => Promise<void>,
  options: BusyRetryOptions = {},
): Promise<void> {
  const { shouldAbort, waker } = options;
  await busyRetryPolicy.withRetry(operation, {
    attempts: MAX_BUSY_RETRIES + 1,
    retryDelaysMs: RETRY_DELAYS_MS,
    shouldAbort,
    sleep: (ms) => abortableSleep(ms, waker),
  });
}

/* ───────────────────────────────────────────────────────────────
   5. WATCHER CORE
──────────────────────────────────────────────────────────────── */

/**
 * Provides the startFileWatcher helper.
 */
export function startFileWatcher(config: WatcherConfig): FSWatcher {
  const watchFactory = config.watchFactory ?? getWatchFactory();

  const debounceMs = config.debounceMs ?? DEFAULT_DEBOUNCE_MS;
  const watchRoots = config.paths.map((watchPath) => path.resolve(watchPath));
  const debounceTimers = new Map<string, NodeJS.Timeout>();
  const contentHashes = new Map<string, string>();
  const canonicalPaths = new Map<string, string>();
  const inFlightReindex = new Set<Promise<void>>();
  let isClosing = false;
  // Wakes in-flight SQLITE_BUSY backoff sleeps on close() so shutdown never
  // blocks on a pending retry timer.
  const retryWaker = createRetryWaker();

  // C3 fix: Bounded concurrency — prevent unbounded parallel reindex operations
  const MAX_CONCURRENT_REINDEX = 2;
  // Cap the pending-slot queue so a runaway watcher event storm
  // can't grow the wait list without bound. 1000 pending entries is generous
  // enough for ordinary workloads (debounceTimers already coalesces by file
  // path upstream so each slot maps to one distinct file's reindex turn) but
  // keeps a runaway loop from leaking memory until OOM. When the queue is at
  // cap the OLDEST waiter is rejected — newer events represent fresher state,
  // and the dropped waiter's caller has its own catch path that tolerates
  // QUEUE_OVERFLOW. On close() every queued waiter is rejected with the same
  // sentinel so dependent code can exit early without hanging.
  const MAX_PENDING_REINDEX_SLOTS = 1000;
  const QUEUE_OVERFLOW_REASON = 'file-watcher reindex queue overflow';
  const QUEUE_CLOSED_REASON = 'file-watcher closed before queued reindex ran';
  interface QueuedSlot {
    readonly resolve: () => void;
    readonly reject: (reason: Error) => void;
  }
  let activeReindexCount = 0;
  const pendingReindexSlots: QueuedSlot[] = [];

  function acquireReindexSlot(): Promise<void> {
    if (isClosing) {
      return Promise.reject(new Error(QUEUE_CLOSED_REASON));
    }
    if (activeReindexCount < MAX_CONCURRENT_REINDEX) {
      activeReindexCount++;
      return Promise.resolve();
    }
    return new Promise((resolve, reject) => {
      // Drop the oldest waiter when the queue is at cap; the
      // displaced waiter's wrapping operation should treat the sentinel error
      // as a recoverable signal (skip this round, debounce will re-fire on the
      // next change).
      if (pendingReindexSlots.length >= MAX_PENDING_REINDEX_SLOTS) {
        const dropped = pendingReindexSlots.shift();
        if (dropped) {
          dropped.reject(new Error(QUEUE_OVERFLOW_REASON));
        }
      }
      pendingReindexSlots.push({
        resolve: () => { activeReindexCount++; resolve(); },
        reject,
      });
    });
  }

  function releaseReindexSlot(): void {
    activeReindexCount--;
    const next = pendingReindexSlots.shift();
    if (next) next.resolve();
  }

  // Drain the pending-slot queue on close() so the watcher does
  // not silently leak Promises. Every queued waiter rejects with the same
  // sentinel; the wrapping `operation()` catch in scheduleTask logs and exits
  // cleanly. The active count is intentionally NOT decremented here — those
  // slots are owned by in-flight reindex tasks and `releaseReindexSlot()` runs
  // in their finally blocks.
  function abortPendingReindexQueue(): void {
    while (pendingReindexSlots.length > 0) {
      const slot = pendingReindexSlots.shift();
      if (slot) {
        slot.reject(new Error(QUEUE_CLOSED_REASON));
      }
    }
  }

  // AbortController per file path for cancellation of stale reindex
  const activeAbortControllers = new Map<string, AbortController>();

  const trackInFlight = (task: Promise<void>): void => {
    inFlightReindex.add(task);
    void task.finally(() => {
      inFlightReindex.delete(task);
    });
  };

  const watcher = watchFactory(config.paths, {
    ignoreInitial: true,
    awaitWriteFinish: { stabilityThreshold: 1000 },
    ignored: (targetPath: string) => {
      return shouldIgnoreWatchTarget(getWatchScopedPath(targetPath, watchRoots) ?? targetPath);
    },
    followSymlinks: false,
  });

  const scheduleTask = (
    targetPath: unknown,
    operation: () => Promise<void>,
  ): void => {
    if (typeof targetPath !== 'string') {
      return;
    }
    if (isClosing) {
      return;
    }

    const filePath = targetPath;
    const watchScopedPath = getWatchScopedPath(filePath, watchRoots);

    if (!isMarkdownPath(filePath) || shouldIgnoreWatchTarget(watchScopedPath ?? filePath)) {
      return;
    }

    const existing = debounceTimers.get(filePath);
    if (existing) {
      clearTimeout(existing);
    }

    const timeout = setTimeout(() => {
      debounceTimers.delete(filePath);
      if (isClosing) {
        return;
      }

      const task = operation().catch((error: unknown) => {
        const message = error instanceof Error ? error.message : String(error);
        // Queue-overflow and queue-closed errors are expected
        // outcomes of the bounded-queue policy, not failures. Log them at a
        // lower severity so storms do not drown legitimate task warnings.
        if (message === QUEUE_OVERFLOW_REASON || message === QUEUE_CLOSED_REASON) {
          console.error(`[file-watcher] Skipped queued reindex for ${path.basename(filePath)}: ${message}`);
          return;
        }
        console.warn(`[file-watcher] Watch task failed for ${path.basename(filePath)}: ${message}`);
      });
      trackInFlight(task);
    }, debounceMs);

    debounceTimers.set(filePath, timeout);
  };

  const scheduleReindex = (targetPath: unknown, options: { force?: boolean } = {}): void => {
    const filePath = typeof targetPath === 'string' ? targetPath : null;
    const forceReindex = options.force === true;

    // Abort any in-flight reindex for this same file before scheduling new one
    if (filePath) {
      const prev = activeAbortControllers.get(filePath);
      if (prev) prev.abort();
    }

    scheduleTask(targetPath, async () => {
      if (!filePath) {
        return;
      }

      const controller = new AbortController();
      activeAbortControllers.set(filePath, controller);

      try {
        let resolvedPath: string;
        try {
          resolvedPath = await fs.realpath(filePath);
        } catch (realpathErr: unknown) {
          const code = realpathErr instanceof Error && 'code' in realpathErr && typeof realpathErr.code === 'string'
            ? realpathErr.code
            : undefined;
          if (code === 'ENOENT') return;
          throw realpathErr;
        }

        if (controller.signal.aborted) return;
        activeAbortControllers.set(resolvedPath, controller);
        canonicalPaths.set(filePath, resolvedPath);
        canonicalPaths.set(resolvedPath, resolvedPath);

        const containmentRoots = await Promise.all(config.paths.map(async (root) => {
          const normalizedRoot = path.resolve(root);
          try {
            return await fs.realpath(normalizedRoot);
          } catch (rootErr: unknown) {
            const code = rootErr instanceof Error && 'code' in rootErr && typeof rootErr.code === 'string'
              ? rootErr.code
              : undefined;
            if (code === 'ENOENT') return normalizedRoot;
            throw rootErr;
          }
        }));
        const isContained = containmentRoots.some((root) => {
          const rootPrefix = root.endsWith(path.sep) ? root : `${root}${path.sep}`;
          return resolvedPath === root || resolvedPath.startsWith(rootPrefix);
        });
        if (!isContained) {
          console.warn(`[file-watcher] Skipping reindex outside watch roots: ${path.basename(filePath)}`);
          return;
        }

        // Handle ENOENT gracefully when a file is rapidly
        // Created then deleted before the debounce timer fires.
        let nextHash: string;
        try {
          nextHash = await hashFileContent(resolvedPath);
        } catch (hashErr: unknown) {
          const code = hashErr instanceof Error && 'code' in hashErr && typeof hashErr.code === 'string'
            ? hashErr.code
            : undefined;
          if (code === 'ENOENT') return; // File was deleted — silently ignore
          throw hashErr;
        }

        if (controller.signal.aborted) return;

        if (!forceReindex) {
          const previousHash = contentHashes.get(resolvedPath);
          if (previousHash && previousHash === nextHash) {
            return;
          }
        }

        // C3: Acquire concurrency slot before CPU-intensive reindex
        await acquireReindexSlot();
        try {
          if (controller.signal.aborted) return;

          const reindexStart = Date.now();
          await withBusyRetry(async () => {
            await config.reindexFn(resolvedPath);
          }, { shouldAbort: () => isClosing, waker: retryWaker });
          if (isClosing) return;
          const reindexElapsed = Date.now() - reindexStart;
          filesReindexed++;
          totalReindexTimeMs += reindexElapsed;
          console.error(`[file-watcher] Reindexed ${path.basename(resolvedPath)} in ${reindexElapsed}ms (total: ${filesReindexed} files, avg: ${Math.round(totalReindexTimeMs / filesReindexed)}ms)`);

          contentHashes.set(resolvedPath, nextHash);
        } finally {
          releaseReindexSlot();
        }
      } finally {
        if (activeAbortControllers.get(filePath) === controller) {
          activeAbortControllers.delete(filePath);
        }
        const resolvedPath = canonicalPaths.get(filePath);
        if (resolvedPath && activeAbortControllers.get(resolvedPath) === controller) {
          activeAbortControllers.delete(resolvedPath);
        }
      }
    });
  };

  const scheduleRemove = (targetPath: unknown): void => {
    const filePath = typeof targetPath === 'string' ? targetPath : null;

    scheduleTask(targetPath, async () => {
      if (!filePath) {
        return;
      }

      const canonicalPath = canonicalPaths.get(filePath) ?? filePath;
      contentHashes.delete(canonicalPath);
      contentHashes.delete(filePath);
      canonicalPaths.delete(filePath);
      if (canonicalPath !== filePath) {
        canonicalPaths.delete(canonicalPath);
      }
      if (!config.removeFn) {
        return;
      }

      await withBusyRetry(async () => {
        await config.removeFn?.(filePath);
      }, { shouldAbort: () => isClosing, waker: retryWaker });
      if (isClosing) return;
      console.error(`[file-watcher] Removed indexed entries for ${path.basename(filePath)}`);
    });
  };

  watcher.on('add', (targetPath: unknown) => {
    scheduleReindex(targetPath, { force: true });
  });
  watcher.on('change', (targetPath: unknown) => {
    scheduleReindex(targetPath);
  });
  watcher.on('unlink', (targetPath: unknown) => {
    scheduleRemove(targetPath);
  });
  watcher.on('error', (error: unknown) => {
    const message = error instanceof Error ? error.message : String(error);
    console.warn(`[file-watcher] Watcher error: ${message}`);
  });

  const originalClose = watcher.close.bind(watcher);
  watcher.close = async () => {
    isClosing = true;
    for (const timeout of debounceTimers.values()) {
      clearTimeout(timeout);
    }
    debounceTimers.clear();

    // Drop every queued slot waiter before settling in-flight
    // work. The waiters reject with QUEUE_CLOSED_REASON; their wrapping
    // operation()s catch and log without re-entering the watcher.
    abortPendingReindexQueue();

    // Wake any in-flight SQLITE_BUSY backoff sleeps so a task mid-retry exits
    // immediately (it re-checks isClosing) instead of holding close() until a
    // non-cancellable retry timer expires.
    retryWaker.wakeAll();

    while (inFlightReindex.size > 0) {
      await Promise.allSettled(Array.from(inFlightReindex));
    }

    await originalClose();
  };

  return watcher;
}

/* ───────────────────────────────────────────────────────────────
   6. EXPORTS
──────────────────────────────────────────────────────────────── */

/**
 * Defines the __testables constant.
 */
export const __testables = {
  getWatchScopedPath,
  isDotfilePath,
  isMarkdownPath,
  shouldIgnoreWatchTarget,
  isSqliteBusyError,
  resetWatcherMetrics,
};

